// Generate contract draft (Thai) via Google Gemini.
import { z } from "npm:zod@3";
import { createClient } from "npm:@supabase/supabase-js@2";
import {
  GeminiError,
  defaultModel,
  geminiGenerateText,
  getGeminiApiKey,
  normalizeGeminiModel,
} from "./gemini.ts";
import { debitAiQuota, getAiUsageSummary } from "./ai-quota.ts";

const CONTRACT_FEATURE = "generate_contract";
const CONTRACT_COST = 8;

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
  "Access-Control-Allow-Methods": "POST, OPTIONS",
};

const SUPABASE_URL = Deno.env.get("SUPABASE_URL")!;
const SUPABASE_ANON_KEY = Deno.env.get("SUPABASE_ANON_KEY")!;

const PayloadSchema = z.object({
  type: z.enum(["project", "fulltime"]),
  hirer_name: z.string().max(200).optional(),
  hirer_id: z.string().max(50).optional(),
  hirer_address: z.string().max(500).optional(),
  contractor_name: z.string().max(200).optional(),
  contractor_id: z.string().max(50).optional(),
  contractor_address: z.string().max(500).optional(),
  job_title: z.string().max(300).optional(),
  scope: z.string().max(4000).optional(),
  deliverables: z.string().max(4000).optional(),
  start_date: z.string().max(40).optional(),
  end_date: z.string().max(40).optional(),
  payment_amount: z.string().max(100).optional(),
  payment_terms: z.string().max(2000).optional(),
  currency: z.string().max(10).optional(),
  ip_owner: z.enum(["hirer", "contractor", "shared"]).optional(),
  nda: z.boolean().optional(),
  termination_notice_days: z.number().int().min(0).max(365).optional(),
  governing_law: z.string().max(200).optional(),
  extra_notes: z.string().max(2000).optional(),
});

type Payload = z.infer<typeof PayloadSchema>;

function buildPrompt(p: Payload): string {
  const isProject = p.type === "project";
  return [
    `คุณเป็นที่ปรึกษากฎหมายไทย ช่วยร่างสัญญา${isProject ? "จ้างทำของ (รายโปรเจกต์/Freelance)" : "จ้างแรงงาน (พนักงานประจำ)"}เป็นภาษาไทย`,
    `ใช้ภาษากฎหมายที่ถูกต้องตามประมวลกฎหมายแพ่งและพาณิชย์ของไทย แต่อ่านง่าย`,
    `ส่งออกเป็น Markdown เท่านั้น มีหัวข้อ ## และข้อย่อย 1. 2. 3.`,
    `ขึ้นต้นด้วยชื่อสัญญา วันที่ ผู้ว่าจ้าง ผู้รับจ้าง แล้วตามด้วยข้อสัญญา`,
    isProject
      ? `ต้องมีหัวข้ออย่างน้อย: ขอบเขตงาน, ส่งมอบงาน, ค่าจ้างและการชำระเงิน, ทรัพย์สินทางปัญญา, การรักษาความลับ, การแก้ไข/ยกเลิก, การระงับข้อพิพาท, ลายมือชื่อ`
      : `ต้องมีหัวข้ออย่างน้อย: ตำแหน่งงานและหน้าที่, ระยะเวลาทดลองงาน, เงินเดือนและสวัสดิการ, เวลาทำงาน, วันหยุดและวันลา, ทรัพย์สินทางปัญญา, การรักษาความลับ, การเลิกจ้าง (แจ้งล่วงหน้า ${p.termination_notice_days ?? 30} วัน), ลายมือชื่อ`,
    `ข้อมูลที่ผู้ใช้กรอกมา (ใช้เติมในสัญญา ห้ามสมมติเกินจริง ถ้าช่องไหนว่างให้ใส่ "[โปรดระบุ]"):`,
    "```json",
    JSON.stringify(p, null, 2),
    "```",
    `หมายเหตุท้ายร่าง: ระบุชัดเจนว่า "เอกสารนี้เป็นเพียงร่างเบื้องต้น ควรให้ทนายความตรวจสอบก่อนใช้งานจริง"`,
  ].join("\n");
}

const json = (body: unknown, status = 200) =>
  new Response(JSON.stringify(body), {
    status,
    headers: { ...corsHeaders, "Content-Type": "application/json" },
  });

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") return new Response("ok", { headers: corsHeaders });
  if (req.method !== "POST") return json({ error: "method not allowed" }, 405);

  // --- Auth ---
  const authHeader = req.headers.get("Authorization");
  if (!authHeader?.startsWith("Bearer ")) return json({ error: "unauthorized" }, 401);
  const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY, {
    global: { headers: { Authorization: authHeader } },
  });
  const token = authHeader.slice("Bearer ".length);
  const { data: claims, error: authErr } = await supabase.auth.getClaims(token);
  if (authErr || !claims?.claims?.sub) return json({ error: "unauthorized" }, 401);

  // --- Validate input ---
  let raw: unknown;
  try {
    raw = await req.json();
  } catch {
    return json({ error: "invalid json body" }, 400);
  }
  const parsed = PayloadSchema.safeParse(raw);
  if (!parsed.success) return json({ error: parsed.error.flatten().fieldErrors }, 400);

  const userId = claims.claims.sub as string;
  const summary = await getAiUsageSummary(userId);
  if ((summary.total_remaining ?? 0) < CONTRACT_COST) {
    return json({ error: "limit_reached", ...summary }, 429);
  }

  try {
    const model = normalizeGeminiModel("google/gemini-2.5-flash", defaultModel());
    const draft = await geminiGenerateText(getGeminiApiKey(), model, {
      messages: [
        { role: "system", content: "คุณเป็นผู้ช่วยร่างสัญญาภาษาไทย ตอบเป็น Markdown เท่านั้น" },
        { role: "user", content: buildPrompt(parsed.data) },
      ],
      temperature: 0.3,
    });

    const quota = await debitAiQuota(userId, CONTRACT_FEATURE, crypto.randomUUID());
    if (!quota.allowed) {
      return json({ error: "limit_reached", ...quota }, 429);
    }

    return json({ draft });
  } catch (e) {
    if (e instanceof GeminiError && e.status === 429) {
      return json({ error: "ใช้งานเยอะเกินไป ลองใหม่อีกครั้ง" }, 429);
    }
    return json({ error: "internal error" }, 500);
  }
});

// Shared Google Gemini client for Supabase Edge Functions (Deno).
// Uses the Generative Language REST API — no Lovable gateway.

const GEMINI_BASE = "https://generativelanguage.googleapis.com/v1beta";

export type GeminiChatRole = "user" | "model";

export interface GeminiChatMessage {
  role: "system" | "user" | "assistant";
  content: string;
}

export class GeminiError extends Error {
  constructor(
    message: string,
    readonly status: number,
  ) {
    super(message);
    this.name = "GeminiError";
  }
}

export function getGeminiApiKey(): string {
  const key = Deno.env.get("GEMINI_API_KEY");
  if (!key) throw new GeminiError("GEMINI_API_KEY not configured", 500);
  return key;
}

export function defaultFastModel(): string {
  return Deno.env.get("GEMINI_MODEL_FAST") ?? "gemini-2.5-flash-lite";
}

export function defaultModel(): string {
  return Deno.env.get("GEMINI_MODEL") ?? "gemini-2.5-flash";
}

export function defaultEmbeddingModel(): string {
  return Deno.env.get("GEMINI_EMBEDDING_MODEL") ?? "text-embedding-004";
}

/** Map legacy Lovable gateway model ids to Gemini API model ids. */
export function normalizeGeminiModel(model?: string, fallback?: string): string {
  if (!model?.trim()) return fallback ?? defaultFastModel();
  let m = model.trim();
  if (m.startsWith("google/")) m = m.slice(7);
  const ALIASES: Record<string, string> = {
    "gemini-3.1-flash-lite-preview": "gemini-2.5-flash-lite",
    "gemini-3-flash-preview": "gemini-2.5-flash",
    "gemini-2.0-flash-lite": "gemini-2.5-flash-lite",
    "gemini-2.0-flash": "gemini-2.5-flash",
    "gemini-2.5-flash-lite": "gemini-2.5-flash-lite",
    "gemini-2.5-flash": "gemini-2.5-flash",
    "openai/text-embedding-3-small": "text-embedding-004",
  };
  return ALIASES[m] ?? m;
}

function splitMessages(messages: GeminiChatMessage[]) {
  const systemLines: string[] = [];
  const contents: Array<{ role: GeminiChatRole; parts: Array<{ text: string }> }> = [];
  for (const msg of messages) {
    if (msg.role === "system") {
      systemLines.push(msg.content);
      continue;
    }
    contents.push({
      role: msg.role === "assistant" ? "model" : "user",
      parts: [{ text: msg.content }],
    });
  }
  return {
    systemInstruction: systemLines.length
      ? { parts: [{ text: systemLines.join("\n\n") }] }
      : undefined,
    contents,
  };
}

function buildRequestBody(opts: {
  messages: GeminiChatMessage[];
  temperature?: number;
  maxOutputTokens?: number;
  json?: boolean;
  tools?: unknown[];
  toolConfig?: Record<string, unknown>;
}) {
  const { systemInstruction, contents } = splitMessages(opts.messages);
  const body: Record<string, unknown> = { contents };
  if (systemInstruction) body.systemInstruction = systemInstruction;
  const gen: Record<string, unknown> = {};
  if (opts.temperature != null) gen.temperature = opts.temperature;
  if (opts.maxOutputTokens != null) gen.maxOutputTokens = opts.maxOutputTokens;
  if (opts.json) gen.responseMimeType = "application/json";
  if (Object.keys(gen).length > 0) body.generationConfig = gen;
  if (opts.tools?.length) body.tools = opts.tools;
  if (opts.toolConfig) body.toolConfig = opts.toolConfig;
  return body;
}

function extractTextFromResponse(json: Record<string, unknown>): string {
  const candidates = json.candidates as Array<Record<string, unknown>> | undefined;
  const parts = (candidates?.[0]?.content as Record<string, unknown> | undefined)?.parts as
    | Array<Record<string, unknown>>
    | undefined;
  if (!parts?.length) return "";
  return parts.map((p) => String(p.text ?? "")).join("");
}

async function parseGeminiError(res: Response): Promise<GeminiError> {
  const t = await res.text().catch(() => "");
  if (res.status === 429) return new GeminiError("rate_limited", 429);
  if (res.status === 401 || res.status === 403) {
    return new GeminiError("GEMINI_API_KEY ไม่ถูกต้องหรือไม่มีสิทธิ์", res.status);
  }
  return new GeminiError(`gemini_error: ${res.status} ${t.slice(0, 200)}`, res.status);
}

export async function geminiGenerateText(
  apiKey: string,
  model: string,
  options: {
    messages: GeminiChatMessage[];
    temperature?: number;
    maxOutputTokens?: number;
    json?: boolean;
  },
): Promise<string> {
  const url = `${GEMINI_BASE}/models/${model}:generateContent?key=${encodeURIComponent(apiKey)}`;
  const res = await fetch(url, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(buildRequestBody(options)),
  });
  if (!res.ok) throw await parseGeminiError(res);
  const json = (await res.json()) as Record<string, unknown>;
  return extractTextFromResponse(json).trim();
}

function extractStreamDelta(json: Record<string, unknown>): string {
  const candidates = json.candidates as Array<Record<string, unknown>> | undefined;
  const parts = (candidates?.[0]?.content as Record<string, unknown> | undefined)?.parts as
    | Array<Record<string, unknown>>
    | undefined;
  if (!parts?.length) return "";
  return parts.map((p) => String(p.text ?? "")).join("");
}

/** Stream Gemini output as So1o SSE (`data: {"delta":"..."}`). */
export function geminiStreamAsSo1oSse(
  apiKey: string,
  model: string,
  messages: GeminiChatMessage[],
): ReadableStream<Uint8Array> {
  const { systemInstruction, contents } = splitMessages(messages);
  const url =
    `${GEMINI_BASE}/models/${model}:streamGenerateContent?alt=sse&key=${encodeURIComponent(apiKey)}`;
  const reqBody: Record<string, unknown> = { contents };
  if (systemInstruction) reqBody.systemInstruction = systemInstruction;

  const encoder = new TextEncoder();
  return new ReadableStream({
    async start(controller) {
      const res = await fetch(url, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(reqBody),
      });
      if (!res.ok) {
        controller.error(await parseGeminiError(res));
        return;
      }
      const reader = res.body?.getReader();
      if (!reader) {
        controller.error(new GeminiError("empty stream", 500));
        return;
      }
      const decoder = new TextDecoder();
      let buffer = "";
      try {
        while (true) {
          const { value, done } = await reader.read();
          if (done) break;
          buffer += decoder.decode(value, { stream: true });
          const lines = buffer.split("\n");
          buffer = lines.pop() ?? "";
          for (const line of lines) {
            if (!line.startsWith("data:")) continue;
            const payload = line.slice(5).trim();
            if (!payload || payload === "[DONE]") continue;
            try {
              const chunk = JSON.parse(payload) as Record<string, unknown>;
              const delta = extractStreamDelta(chunk);
              if (delta) {
                controller.enqueue(
                  encoder.encode(`data: ${JSON.stringify({ delta })}\n\n`),
                );
              }
            } catch {
              /* ignore malformed chunk */
            }
          }
        }
      } finally {
        controller.close();
      }
    },
  });
}

/** Structured output via Gemini function calling. */
export async function geminiGenerateWithFunction(
  apiKey: string,
  model: string,
  options: {
    messages: GeminiChatMessage[];
    functionName: string;
    description: string;
    functionSchema: Record<string, unknown>;
    temperature?: number;
  },
): Promise<Record<string, unknown>> {
  const { systemInstruction, contents } = splitMessages(options.messages);
  const body: Record<string, unknown> = {
    contents,
    tools: [{
      functionDeclarations: [{
        name: options.functionName,
        description: options.description,
        parameters: options.functionSchema,
      }],
    }],
    toolConfig: {
      functionCallingConfig: {
        mode: "ANY",
        allowedFunctionNames: [options.functionName],
      },
    },
  };
  if (systemInstruction) body.systemInstruction = systemInstruction;
  if (options.temperature != null) {
    body.generationConfig = { temperature: options.temperature };
  }

  const url = `${GEMINI_BASE}/models/${model}:generateContent?key=${encodeURIComponent(apiKey)}`;
  const res = await fetch(url, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });
  if (!res.ok) throw await parseGeminiError(res);

  const json = (await res.json()) as Record<string, unknown>;
  const parts = ((json.candidates as Array<Record<string, unknown>> | undefined)?.[0]
    ?.content as Record<string, unknown> | undefined)?.parts as
    | Array<Record<string, unknown>>
    | undefined;

  for (const part of parts ?? []) {
    const fc = part.functionCall as { name?: string; args?: Record<string, unknown> } | undefined;
    if (fc?.args && typeof fc.args === "object") return fc.args;
  }

  const text = extractTextFromResponse(json);
  if (text) {
    try {
      return JSON.parse(text) as Record<string, unknown>;
    } catch {
      throw new GeminiError("invalid function json", 500);
    }
  }
  throw new GeminiError("empty function response", 500);
}

export async function geminiEmbedText(
  apiKey: string,
  text: string,
  model?: string,
): Promise<number[]> {
  const m = normalizeGeminiModel(model, defaultEmbeddingModel());
  const url = `${GEMINI_BASE}/models/${m}:embedContent?key=${encodeURIComponent(apiKey)}`;
  const res = await fetch(url, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      content: { parts: [{ text }] },
    }),
  });
  if (!res.ok) throw await parseGeminiError(res);
  const json = (await res.json()) as Record<string, unknown>;
  const embedding = json.embedding as Record<string, unknown> | undefined;
  const values = embedding?.values as number[] | undefined;
  if (!values?.length) throw new GeminiError("empty embedding", 500);
  return values;
}

// Shared AI credits guard for edge functions.
// Backed by public.debit_ai_credits(user_id, feature, environment, idempotency_key) RPC.
import { createClient } from "https://esm.sh/@supabase/supabase-js@2.45.0";

export interface QuotaResult {
  allowed: boolean;
  cost?: number;
  included_used?: number;
  included_limit?: number;
  included_remaining?: number;
  purchased_balance?: number;
  total_remaining?: number;
  reason?: string;
}

function paymentsEnv(): "sandbox" | "live" {
  const env = Deno.env.get("STRIPE_ENVIRONMENT");
  return env === "live" ? "live" : "sandbox";
}

export async function getAiUsageSummary(userId: string): Promise<QuotaResult & { total_remaining?: number }> {
  const SUPABASE_URL = Deno.env.get("SUPABASE_URL");
  const SERVICE_KEY = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
  if (!SUPABASE_URL || !SERVICE_KEY) {
    return { allowed: false, reason: "server_misconfiguration", total_remaining: 0 };
  }
  const admin = createClient(SUPABASE_URL, SERVICE_KEY);
  const { data, error } = await admin.rpc("get_ai_usage_summary", {
    _user_id: userId,
    _environment: paymentsEnv(),
  });
  if (error) {
    console.error("[ai-quota] summary rpc error", error.message);
    return { allowed: false, reason: "quota_check_failed", total_remaining: 0 };
  }
  return data as QuotaResult & { total_remaining?: number };
}

/**
 * Atomically debit AI credits for a user/feature.
 * Returns quota summary. When `allowed` is false the caller MUST short-circuit.
 */
export async function debitAiQuota(
  userId: string,
  feature: string,
  idempotencyKey?: string,
): Promise<QuotaResult> {
  const SUPABASE_URL = Deno.env.get("SUPABASE_URL");
  const SERVICE_KEY = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
  if (!SUPABASE_URL || !SERVICE_KEY) {
    return { allowed: false, reason: "server_misconfiguration" };
  }
  const admin = createClient(SUPABASE_URL, SERVICE_KEY);
  const { data, error } = await admin.rpc("debit_ai_credits", {
    _user_id: userId,
    _feature: feature,
    _environment: paymentsEnv(),
    _idempotency_key: idempotencyKey ?? null,
  });
  if (error) {
    console.error(`[ai-quota:${feature}] rpc error`, error.message);
    return { allowed: false, reason: "quota_check_failed" };
  }
  return data as QuotaResult;
}

/** @deprecated Use debitAiQuota — kept for gradual migration */
export async function checkAiQuota(
  userId: string,
  feature: string,
  _isPro: boolean,
): Promise<QuotaResult & { count: number; limit: number }> {
  const result = await debitAiQuota(userId, feature);
  return {
    ...result,
    count: result.included_used ?? 0,
    limit: result.included_limit ?? 0,
  };
}

/** Returns true if the user has an active Pro/Inhouse subscription. */
export async function isProUser(userId: string): Promise<boolean> {
  const SUPABASE_URL = Deno.env.get("SUPABASE_URL");
  const SERVICE_KEY = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
  if (!SUPABASE_URL || !SERVICE_KEY) return false;
  const admin = createClient(SUPABASE_URL, SERVICE_KEY);
  const { data } = await admin
    .from("profiles")
    .select("subscription_tier")
    .eq("user_id", userId)
    .maybeSingle();
  const tier = (data?.subscription_tier ?? "free") as string;
  return tier === "pro" || tier === "inhouse";
}
